import React, { Fragment, useContext, useState, useEffect } from "react";
import { ProductContext } from "./index";
import { createProduct, getAllProduct } from "./FetchApi";
import { getAllCategory } from "../categories/FetchApi";

const AddProductDetail = ({ categories }) => {
  const { data, dispatch } = useContext(ProductContext);

  const alert = (msg, type) => (
    <div className={`bg-${type}-200 py-2 px-4 w-full`}>{msg}</div>
  );

  const [fData, setFdata] = useState({
    pTimeWindowHours: "",
    pDescription: "",
    pStatus: "Active",
    pImage: [], // Initial value will be null or empty array
    pCategory: "",
    pPrice: "",
    pOffer: 0,
    pQuantity: "",
    pMedicalReport: null,
    success: false,
    error: false,
  });

  const fetchData = async () => {
    let responseData = await getAllProduct();
    setTimeout(() => {
      if (responseData && responseData.Products) {
        dispatch({
          type: "fetchProductsAndChangeState",
          payload: responseData.Products,
        });
      }
    }, 1000);
  };

  const submitForm = async (e) => {
    e.preventDefault();
    e.persist();


    if (fData.pImage.length < 1) {
      
      setFdata({ ...fData, error: "Please upload at least 1 image" });
      setTimeout(() => {
        setFdata({ ...fData, error: false });
      }, 2000);
      return;
    }

    const formData = new FormData();
    formData.append("pTimeWindowHours", fData.pTimeWindowHours);
    formData.append("pDescription", fData.pDescription);
    formData.append("pStatus", fData.pStatus);
    for (const image of fData.pImage) {
      formData.append("pImage", image);
    }
    formData.append("pCategory", fData.pCategory);
    formData.append("pPrice", fData.pPrice);
    formData.append("pOffer", fData.pOffer);
    formData.append("pQuantity", fData.pQuantity);
    if (fData.pMedicalReport) {
      formData.append("pMedicalReport", fData.pMedicalReport);
    }

    try {
      // Get current user ID from localStorage
      const currentUser = JSON.parse(localStorage.getItem("jwt"));
      formData.append("user", currentUser ? currentUser.user._id : null);

      let responseData = await createProduct(formData);
      
      if (responseData.success) {
        e.target.reset();
        setFdata({
          ...fData,
          pTimeWindowHours: "",
          pDescription: "",
          pImage: [],
          pStatus: "Active",
          pCategory: "",
          pPrice: "",
          pQuantity: "",
          pOffer: 0,
          pMedicalReport: null,
          success: responseData.success,
          error: false,
        });
        setTimeout(() => {
          setFdata({
            ...fData,
            pTimeWindowHours: "",
            pDescription: "",
            pImage: [],
            pStatus: "Active",
            pCategory: "",
            pPrice: "",
            pQuantity: "",
            pOffer: 0,
            pMedicalReport: null,
            success: false,
            error: false,
          });
          dispatch({ type: "addProductModal", payload: false });
        }, 2000);
      } else if (responseData.error) {
        setFdata({ ...fData, success: false, error: responseData.error });
        setTimeout(() => {
          setFdata({ ...fData, error: false, success: false });
        }, 2000);
      }
    } catch (error) {
      console.error("Error in submitForm:", error);
    }
      
  };

  return (
    <Fragment>
      {/* Black Overlay */}
      <div
        onClick={(e) => dispatch({ type: "addProductModal", payload: false })}
        className={`${
          data.addProductModal ? "" : "hidden"
        } fixed top-0 left-0 z-30 w-full h-full bg-black opacity-50`}
      />
      {/* End Black Overlay */}

      {/* Modal Start */}
      <div
        className={`${
          data.addProductModal ? "" : "hidden"
        } fixed inset-0 flex items-center z-30 justify-center overflow-auto`}
      >
        <div className="mt-32 md:mt-0 relative bg-white w-11/12 md:w-3/6 shadow-lg flex flex-col items-center space-y-4 px-4 py-4 md:px-8">
          <div className="flex items-center justify-between w-full pt-4">
            <span className="text-left font-semibold text-2xl tracking-wider">
              Add Organ
            </span>
            {/* Close Modal */}
            <span
              style={{ background: "#303031" }}
              onClick={(e) =>
                dispatch({ type: "addProductModal", payload: false })
              }
              className="cursor-pointer text-gray-100 py-2 px-2 rounded-full"
            >
              <svg
                className="w-6 h-6"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
                xmlns="http://www.w3.org/2000/svg"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M6 18L18 6M6 6l12 12"
                />
              </svg>
            </span>
          </div>
          {fData.error ? alert(fData.error, "red") : ""}
          {fData.success ? alert(fData.success, "green") : ""}
          <form className="w-full" onSubmit={(e) => submitForm(e)}>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 py-4">
              <div className="flex flex-col space-y-1">
                <label htmlFor="timeWindow">Time Window *</label>
                <div className="flex items-center">
                  <input
                    value={fData.pTimeWindowHours}
                    onChange={(e) =>
                      setFdata({
                        ...fData,
                        error: false,
                        success: false,
                        pTimeWindowHours: e.target.value,
                      })
                    }
                    className="px-4 py-2 border focus:outline-none w-full"
                    type="number"
                    id="timeWindow"
                  />
                  <span className="ml-2">hrs</span>
                </div>
              </div>
              <div className="flex flex-col space-y-1">
                <label htmlFor="price">PIN Code *</label>
                <input
                  value={fData.pPrice}
                  onChange={(e) =>
                    setFdata({
                      ...fData,
                      error: false,
                      success: false,
                      pPrice: e.target.value,
                    })
                  }
                  type="number"
                  className="px-4 py-2 border focus:outline-none"
                  id="price"
                />
              </div>
              <div className="flex flex-col space-y-2 md:col-span-2">
                <label htmlFor="description">Organ Description *</label>
                <textarea
                  value={fData.pDescription}
                  onChange={(e) =>
                    setFdata({
                      ...fData,
                      error: false,
                      success: false,
                      pDescription: e.target.value,
                    })
                  }
                  className="px-4 py-2 border focus:outline-none"
                  name="description"
                  id="description"
                  cols={5}
                  rows={2}
                />
              </div>
              {/* Most Important part for uploading multiple image */}
              <div className="flex flex-col mt-4 md:col-span-2">
                <label htmlFor="image">Organ Images *</label>
                <span className="text-gray-600 text-xs">Must need 1 image</span>
                <input
                  onChange={(e) =>
                    setFdata({
                      ...fData,
                      error: false,
                      success: false,
                      pImage: [...e.target.files],
                    })
                  }
                  type="file"
                  accept=".jpg, .jpeg, .png"
                  className="px-4 py-2 border focus:outline-none"
                  id="image"
                  multiple
                />
              </div>
              {/* Most Important part for uploading multiple image */}
              <div className="flex flex-col mt-4 md:col-span-2">
                <label htmlFor="medicalReport">Patient Medical Report</label>
                <input
                  onChange={(e) =>
                    setFdata({
                      ...fData,
                      error: false,
                      success: false,
                      pMedicalReport: e.target.files[0],
                    })
                  }
                  type="file"
                  accept=".pdf, .doc, .docx, .jpg, .jpeg, .png"
                  className="px-4 py-2 border focus:outline-none"
                  id="medicalReport"
                />
              </div>
              <div className="flex flex-col space-y-1">
                <label htmlFor="status">Organ Status *</label>
                <select
                  value={fData.pStatus}
                  onChange={(e) =>
                    setFdata({
                      ...fData,
                      error: false,
                      success: false,
                      pStatus: e.target.value,
                    })
                  }
                  name="status"
                  className="px-4 py-2 border focus:outline-none"
                  id="status"
                >
                  <option name="status" value="Active">
                    Active
                  </option>
                  <option name="status" value="Disabled">
                    Disabled
                  </option>
                </select>
              </div>
              <div className="flex flex-col space-y-1">
                <label htmlFor="status">Organ Category *</label>
                <select
                  value={fData.pCategory}
                  onChange={(e) =>
                    setFdata({
                      ...fData,
                      error: false,
                      success: false,
                      pCategory: e.target.value,
                    })
                  }
                  name="status"
                  className="px-4 py-2 border focus:outline-none"
                  id="status"
                >
                  <option disabled value="">
                    Select a category
                  </option>
                  {categories.length > 0
                    ? categories.map(function (elem) {
                        return (
                          <option name="status" value={elem._id} key={elem._id}>
                            {elem.cName}
                          </option>
                        );
                      })
                    : ""}
                </select>
              </div>
              <div className="flex flex-col space-y-1">
                <label htmlFor="quantity">Units Available *</label>
                <input
                  value={fData.pQuantity}
                  onChange={(e) =>
                    setFdata({
                      ...fData,
                      error: false,
                      success: false,
                      pQuantity: e.target.value,
                    })
                  }
                  type="number"
                  className="px-4 py-2 border focus:outline-none"
                  id="quantity"
                />
              </div>
              {/* <div className="w-1/2 flex flex-col space-y-1">
                <label htmlFor="offer">Product Offfer (%) *</label>
                <input
                  value={fData.pOffer}
                  onChange={(e) =>
                    setFdata({
                      ...fData,
                      error: false,
                      success: false,
                      pOffer: e.target.value,
                    })
                  }
                  type="number"
                  className="px-4 py-2 border focus:outline-none"
                  id="offer"
                />
              </div> */}
              <div className="flex flex-col space-y-1 w-full pb-4 md:pb-6 mt-4 md:col-span-2">
                <button
                  style={{ background: "#303031" }}
                  type="submit"
                  className="rounded-full bg-gray-800 text-gray-100 text-lg font-medium py-2"
                >
                  Add Organ
                </button>
              </div>
            </div>
          </form>
        </div>
      </div>
    </Fragment>
  );
};

const AddProductModal = (props) => {
  useEffect(() => {
    fetchCategoryData();
  }, []);

  const [allCat, setAllCat] = useState([]);

  const fetchCategoryData = async () => {
    try {
      let responseData = await getAllCategory();
      if (responseData && responseData.Categories) {
        setAllCat(responseData.Categories);
      } else {
        setAllCat([]);
      }
    } catch (err) {
      console.error("fetchCategoryData error", err);
      setAllCat([]);
    }
  };

  return (
    <Fragment>
      <AddProductDetail categories={allCat} />
    </Fragment>
  );
};

export default AddProductModal;
